<span class="line">    <span class="token string">&#39;股票&#39;</span><span class="token punctuation">,</span> symbol<span class="token punctuation">,</span> <span class="token string">&#39;今日收盘价&#39;</span><span class="token punctuation">,</span> close_price<span class="token punctuation">,</span> <span class="token string">&#39;，涨幅&#39;</span><span class="token punctuation">,</span> change_ratio<span class="token punctuation">,</span> <span class="token string">&#39;%，振幅&#39;</span><span class="token punctuation">,</span> amplitude_ratio<span class="token punctuation">,</span> <span class="token string">&#39;%&#39;</span><span class="token punctuation">,</span></span>
