<span class="line">      <span class="token string">&#39;今日上涨&#39;</span><span class="token punctuation">,</span> up_count<span class="token punctuation">,</span> <span class="token string">&#39;，下跌&#39;</span><span class="token punctuation">,</span> down_count<span class="token punctuation">,</span> <span class="token string">&#39;，成交额&#39;</span><span class="token punctuation">,</span> market_amount<span class="token punctuation">,</span></span>
